import{_ as a,o as b,c as t,j as r,a as p,a1 as _}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"智力2才能学会的弩箭使用与保养手册","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/射击类/智力2才能学会的弩箭使用与保养手册.md","filePath":"4.资源分区/6.技艺及称号/射击类/智力2才能学会的弩箭使用与保养手册.md"}'),n={name:"4.资源分区/6.技艺及称号/射击类/智力2才能学会的弩箭使用与保养手册.md"};function s(o,e,d,l,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"智力2才能学会的弩箭使用与保养手册",tabindex:"-1"},[p("智力2才能学会的弩箭使用与保养手册 "),r("a",{class:"header-anchor",href:"#智力2才能学会的弩箭使用与保养手册","aria-label":'Permalink to "智力2才能学会的弩箭使用与保养手册"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风026")])])],-1),_('<h1 id="智力2才能学会的弩箭使用与保养手册-1" tabindex="-1">智力2才能学会的弩箭使用与保养手册 <a class="header-anchor" href="#智力2才能学会的弩箭使用与保养手册-1" aria-label="Permalink to &quot;智力2才能学会的弩箭使用与保养手册&quot;">​</a></h1><p>智力2才能学会的弩箭使用与保养手册<br> 本技艺是让初级弩箭使用者时更加顺手而存在，因此，只是一部分使用弩箭的小技巧与改造，改造分为【弩】与【箭】两部分。<br> 因此你也可以将此技艺称呼为【夏姬八改】<br> 限制：此技艺必须为智力2以上才能强化<br> 特殊：若你附加改造的弩丢失你可以重新指定一把弩获得你已购买的改造<br> ■弩改造<br> 【箭仓扩充】D+500<br> 你还在为抽箭搭箭的浪费时间而苦恼吗？这项技术完美弥补了这一缺点。<br> 购买后你选择一把持有的弩进行改造，此后该弩获得【无限子弹】与【连射】特性，但你任然可以通过正常搭箭并正常消耗弹药从而获得一些额外效果。除此之外你若是具有特殊箭矢则可以通过提前填装来排列好顺序使用，但若是你在战斗中需要卸下或更换箭矢仍需遵守对应动作消耗。<br> 【材质变化】C+1000<br> 更硬的弩，更大的动力，更棒的手感<br> 在进行格挡时，可以使用【射击+弩】/2代替【武技+相关专业】/2来计算获得的格挡防御，你使用弩进行的攻击获得【熔毁2】。每轮一次，当你对使用弩进行的攻击结果不满时可以进行一次重骰，但无论结果如何都必须接受。</p><p>■零件改造</p><p>【强力弩弦】500<br> 该丢掉那磨损的破弦了<br> 你为你的弩换上更新更好的弦这使得你的弩箭更快更利，额外获得1高速与1破甲</p><p>【长枪管】750<br> 要射的更远，只有这样才能更安全更隐蔽，你为你的弩安装上长枪管以此让它射的更远.<br> 你的弩增加1倍基础射程（特殊的此改造与强力枪管在同一把弩上只能具有其中之一）</p><p>【强力枪管】500<br> 箭矢要更有力才能射穿畜生的皮毛<br> 你的弩额外获得2点破甲（特殊的此改造与长枪管在同一把弩上只能具有其中之一）</p><p>【盾牌】500<br> 更加的安全更加的重<br> 你为重弩装上了盾牌，以求保护你的身体，特殊的此改造只能对重弩使用，且改造后该弩的力量需求增加1点，当你手持该弩时在遮蔽等隐藏自己的鉴定上获得2点器械减值。<br> 只要你手持这把弩哪怕你不进行格挡动也会获得2点格挡防御。</p><p>【短刺】250<br> 在没箭和被近身时这就是你的救命稻草。<br> 你的弩装上了把匕首，你可以用这把弩来近战了，但进行的检定仍需遵循匕首的白刃检定，使用武技和匕首专业，短刺的武器伤害为3L。</p><p>■箭改造<br> 【贯穿箭】D+500<br> 精准与穿透<br> 你可以在战斗中可以花费一个迅捷动作将你的弩箭替换为【贯穿箭】，这使得你下一次使用弩进行的攻击获得【贯穿】特性的同时提高获得【破甲5】。</p><p>【锁链箭】D+500<br> 箭支连接锁链<br> 你为箭支接上锁链以求猎物无法逃离<br> 现在你可以花费一个标准动作进行一次攻击，这使得目标与你之间被锁链链接，你可以消耗自由动作对对方进行一次方向为你的拖拽，dc为你这次攻击的出数对方以反射/强韧豁免，拖拽差值*1m。同时在接下来1场景内，对方的移动速度降低25m这是D级创伤来源的效果。</p><p>【淬毒箭】D+500<br> 毒素是以小博大的关键，但稍不注意便会反噬自己<br> 你可以花费移动动作为弩箭淬毒，这会使得你下次攻击会附带1点不可豁免的毒素点数（毒素来源）</p><p>【裂片箭】C+1000<br> 你修改箭头只为让它们在猎物体内开花，破坏脏器。<br> 花费一个移动动作，接下来一场景内，你的弩箭会对攻击者造成B级重伤，同时你可以将攻击中的1点严重伤害转变为韧性伤害，攻击命中时若对方具有能量池则流失2点能量。<br> ■小技巧<br> 【隐蔽】D+500<br> 更加的小心更加的谨慎，那该死畜生可不会给你第二次机会<br> 当你在潜行中时取消潜行行走的速度限制，同时当你在一场影片的战斗中进行过潜藏，当影片结束时你的潜藏鉴定获得1点内在加值。</p><p>【翻滚】D+500<br> 更快，更远，更灵活，让那畜生拿你没办法<br> 在你的回合仅一次，你可以以迅捷动作朝任意方向移动20m。</p><p>【跑酷】D+500<br> 跑吧，跳吧，让都市也变成你的地盘<br> 你现在可以进行跳跃移动且能行走在垂直的平面上但移动结束后仍然需要落脚点。</p><p>【制弩】D+500<br> 这是你必须学会的，虽然它带了些超凡<br> 你可以占用1点你的能量池上限为自己制造一把无支线的弩（同现实-基础远程武器-弩，可自选重弩轻弩。）同时因为是花费你的能量制造其具有无限子弹特性。你可以随机遣散它来恢复你的能量池上限。</p><p>【搏斗】D+500<br> 近身缠斗，弩斗术（）<br> 若你购买了【短刺】则你现在可以使用武技+弩专业来进行白刃检定，同时你的弩获得谐振特性，武器伤害提供的破甲将会该为提供1点格挡防御。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const D=a(n,[["render",s]]);export{m as __pageData,D as default};
